function TeamDashboard({ teamId }) {
  const { data: team } = useQuery(['team', teamId], fetchTeam);
  const { data: members } = useQuery(
    ['members', teamId],
    () => fetchMembers(teamId)
  );

  return (
    <div>
      <h1>{team?.name}</h1>
      {members?.map(member => (
        <MemberCard
          key={member.id}
          member={member}
          // Each card fetches its own stats
        />
      ))}
    </div>
  );
}

function MemberCard({ member }) {
  const { data: stats } = useQuery(
    ['stats', member.id],
    () => fetchMemberStats(member.id)
  );
  return <div>{member.name}: {stats?.commits} commits</div>;
}
