function CommentSection({ postId }) {
  const [comments, setComments] = useState([]);

  useEffect(() => {
    fetch(`/api/posts/${postId}/comments`)
      .then(res => res.json())
      .then(setComments);
  }, [postId]);

  return (
    <div>
      {comments.map(c => (
        <div key={c.id}>
          <p dangerouslySetInnerHTML={{ __html: c.body }} />
          <span>{c.author}</span>
        </div>
      ))}
    </div>
  );
}
